/* CRISC :: content/labs.js — CRISC hands-on sandbox labs (20). */
window.LABS = [
{"id":"Lab 01","num":1,"group":"GOVERNANCE","title":"Draft an IT Risk Management Charter","desc":"A mid-size insurer has never formalized IT risk management; risk decisions are made informally by whichever manager is in the room. The audit committee has asked you to draft a charter that establishes the risk practice's authority and scope before the next board cycle.","objectives":["Anchor the risk management charter to the organization's stated risk appetite","Confirm the charter grants formal authority to identify, assess, and escalate risk","Establish clear reporting lines from the risk function to senior management"],"console":{"host":"crisc-lab01","boot":["[SYS] risk-console v3.0 initializing","[SYS] loading enterprise risk appetite statement","[SYS] charter template attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose what the charter must be anchored to"},{"id":"t2","label":"Choose the authority the charter must grant"},{"id":"t3","label":"Choose the reporting line for the risk function"}],"configs":[{"id":"c1","label":"What should the IT risk charter be anchored to first?","options":["The organization's documented risk appetite and business objectives","The IT department's technology roadmap","Last year's audit findings only","Industry benchmark spending levels"],"correct":"The organization's documented risk appetite and business objectives","task":"t1"},{"id":"c2","label":"What authority must the charter formally grant the risk function?","options":["The ability to identify, assess, and escalate risk across the enterprise","The ability to approve all IT purchases","The ability to discipline employees directly","No formal authority, advisory only"],"correct":"The ability to identify, assess, and escalate risk across the enterprise","task":"t2"},{"id":"c3","label":"To whom should the risk function report for the charter to be effective?","options":["Senior management and the board or a delegated committee","The help desk supervisor","A single IT project manager","No one, it should be fully independent of oversight"],"correct":"Senior management and the board or a delegated committee","task":"t3"}],"payload":{"label":"RUN the charter validation check","placeholder":"validate-charter --scope enterprise-it-risk","button":"Run","response":"[OUT] Charter references board-approved risk appetite statement; escalation authority confirmed across 4 business units; quarterly reporting line to audit committee established. Conclusion: charter is properly anchored and governance-ready."}}},
{"id":"Lab 02","num":2,"group":"GOVERNANCE","title":"Align Risk Appetite with Business Strategy","desc":"A retail chain's leadership approved an aggressive e-commerce expansion but the existing risk appetite statement still reflects a conservative, brick-and-mortar posture. You must reconcile the two before new risk scenarios are logged against a stale baseline.","objectives":["Recognize that risk appetite must be revisited when business strategy changes","Distinguish risk appetite from risk tolerance and risk capacity","Confirm the updated appetite statement is approved by senior management before use"],"console":{"host":"crisc-lab02","boot":["[SYS] risk-console v3.0 initializing","[SYS] loading current risk appetite statement","[SYS] e-commerce strategy brief attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose when risk appetite should be reassessed"},{"id":"t2","label":"Choose the correct distinction between appetite and tolerance"},{"id":"t3","label":"Choose who must approve the revised statement"}],"configs":[{"id":"c1","label":"When should the risk appetite statement be reassessed?","options":["Whenever business strategy or objectives materially change","Only once every five years regardless of business change","Only after a major loss event occurs","Never; the original statement should remain fixed"],"correct":"Whenever business strategy or objectives materially change","task":"t1"},{"id":"c2","label":"How does risk tolerance differ from risk appetite?","options":["Tolerance is the acceptable variation around the appetite level for a specific objective","Tolerance and appetite are identical terms","Tolerance is set only by IT, appetite only by the board","Tolerance applies only to financial risk, appetite to all other risk"],"correct":"Tolerance is the acceptable variation around the appetite level for a specific objective","task":"t2"},{"id":"c3","label":"Who must approve the revised risk appetite statement?","options":["Senior management, ratified by the board","The IT risk analyst who drafted it","The e-commerce vendor","No approval is needed if IT agrees internally"],"correct":"Senior management, ratified by the board","task":"t3"}],"payload":{"label":"RUN the appetite realignment check","placeholder":"realign-appetite --initiative ecommerce-expansion","button":"Run","response":"[OUT] Appetite statement updated to reflect growth strategy; tolerance bands redefined for 3 key objectives; board ratification recorded. Conclusion: risk appetite is realigned with current business strategy."}}},
{"id":"Lab 03","num":3,"group":"GOVERNANCE","title":"Assign Risk Ownership Across Business Units","desc":"An enterprise risk register lists 60 risks but nearly half have no named owner, and several list the CIO as owner regardless of subject matter. You must reassign ownership so accountability sits with the roles that can actually influence treatment decisions.","objectives":["Distinguish risk owners from risk custodians and control operators","Assign ownership to the role with authority over the underlying process or asset","Confirm every risk in scope has exactly one accountable owner"],"console":{"host":"crisc-lab03","boot":["[SYS] risk-console v3.0 initializing","[SYS] loading enterprise risk register (60 entries)","[SYS] RACI matrix attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the correct definition of a risk owner"},{"id":"t2","label":"Choose who ownership should be assigned to"},{"id":"t3","label":"Choose the correct ownership rule per risk"}],"configs":[{"id":"c1","label":"What best defines a risk owner?","options":["The person accountable for ensuring a risk is managed appropriately, including treatment decisions","The person who technically operates a security control","The auditor who last reviewed the risk","Whoever has the most seniority in the company"],"correct":"The person accountable for ensuring a risk is managed appropriately, including treatment decisions","task":"t1"},{"id":"c2","label":"To whom should a specific business-process risk be assigned?","options":["The role with authority over that process or asset","The CIO for every risk regardless of domain","The IT help desk","The external audit firm"],"correct":"The role with authority over that process or asset","task":"t2"},{"id":"c3","label":"How many accountable owners should each risk in the register have?","options":["Exactly one clearly accountable owner","At least three co-owners to spread accountability","Zero; ownership is optional if the risk is low","One owner per control, regardless of the risk"],"correct":"Exactly one clearly accountable owner","task":"t3"}],"payload":{"label":"RUN the ownership assignment sweep","placeholder":"assign-owners --register enterprise --unassigned-only","button":"Run","response":"[OUT] 28 unassigned risks reassigned to accountable process owners; 4 CIO-default entries corrected to business-unit leads; 60/60 risks now have exactly one owner. Conclusion: ownership assignment is complete and defensible."}}},
{"id":"Lab 04","num":4,"group":"GOVERNANCE","title":"Integrate IT Risk into Enterprise Risk Management","desc":"IT risk is tracked in a standalone spreadsheet that never reaches the enterprise risk committee, while operational and financial risks are reviewed quarterly at the board level. You must integrate IT risk reporting into the existing ERM structure rather than running a parallel process.","objectives":["Recognize that IT risk should be integrated into ERM, not managed as a silo","Use a common risk taxonomy and scoring scale across risk domains","Ensure IT risk reporting reaches the same governance body as other enterprise risk"],"console":{"host":"crisc-lab04","boot":["[SYS] risk-console v3.0 initializing","[SYS] loading ERM committee charter","[SYS] IT risk spreadsheet import detected","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the correct integration approach"},{"id":"t2","label":"Choose the scoring approach across risk domains"},{"id":"t3","label":"Choose the reporting destination for IT risk"}],"configs":[{"id":"c1","label":"How should IT risk management relate to enterprise risk management?","options":["It should be integrated into the ERM structure, not run as a separate silo","It should remain fully separate since IT risk is too technical","It should replace ERM entirely","It should only be shared with ERM after an incident occurs"],"correct":"It should be integrated into the ERM structure, not run as a separate silo","task":"t1"},{"id":"c2","label":"What scoring approach allows IT risk to be compared with other enterprise risks?","options":["A common taxonomy and likelihood/impact scale used across all risk domains","A unique scoring scale specific only to IT","No formal scoring, only narrative descriptions","Scoring based solely on technical severity ratings like CVSS"],"correct":"A common taxonomy and likelihood/impact scale used across all risk domains","task":"t2"},{"id":"c3","label":"Where should significant IT risk be reported alongside other enterprise risks?","options":["The same enterprise risk committee or board reviewing operational and financial risk","A separate IT-only steering group with no enterprise visibility","Only in the annual audit report","Nowhere, until the risk becomes an incident"],"correct":"The same enterprise risk committee or board reviewing operational and financial risk","task":"t3"}],"payload":{"label":"RUN the ERM integration mapping","placeholder":"integrate-it-risk --target erm-committee","button":"Run","response":"[OUT] IT risk taxonomy mapped to enterprise scale; 22 IT risks re-scored on common 5x5 matrix; quarterly reporting slot added to ERM committee agenda. Conclusion: IT risk is now integrated into enterprise-level governance."}}},
{"id":"Lab 05","num":5,"group":"GOVERNANCE","title":"Establish Accountability with a RACI for Risk Activities","desc":"A recent internal review found that risk assessments, control testing, and exception approvals are each performed by whoever happens to be available, with no consistent accountability. You must build a RACI model that clarifies who does what across the risk lifecycle.","objectives":["Distinguish Responsible, Accountable, Consulted, and Informed roles in risk activities","Ensure each risk activity has exactly one Accountable party","Confirm the RACI model is approved and communicated to all stakeholders"],"console":{"host":"crisc-lab05","boot":["[SYS] risk-console v3.0 initializing","[SYS] loading risk lifecycle activity list","[SYS] stakeholder directory attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the correct meaning of the Accountable role"},{"id":"t2","label":"Choose the correct number of Accountable parties per activity"},{"id":"t3","label":"Choose the final step after the RACI is built"}],"configs":[{"id":"c1","label":"What does the Accountable role in a RACI represent?","options":["The single person who ultimately answers for the activity's outcome","Anyone who performs part of the task","Anyone who must be kept informed after the fact","The person consulted for technical input only"],"correct":"The single person who ultimately answers for the activity's outcome","task":"t1"},{"id":"c2","label":"How many people should be Accountable for a single risk activity?","options":["Exactly one","As many as are involved in the task","Zero, accountability is collective","Two, so there is a backup"],"correct":"Exactly one","task":"t2"},{"id":"c3","label":"What should happen after the RACI model is finalized?","options":["It is approved by management and communicated to all stakeholders","It is filed away and referenced only during audits","It is kept confidential from staff to avoid disputes","It replaces the need for a risk charter"],"correct":"It is approved by management and communicated to all stakeholders","task":"t3"}],"payload":{"label":"RUN the RACI consistency check","placeholder":"validate-raci --scope risk-lifecycle","button":"Run","response":"[OUT] 12 risk activities mapped; each activity has exactly one Accountable role; RACI approved by risk committee and distributed to 9 stakeholder groups. Conclusion: accountability model is consistent and communicated."}}},
{"id":"Lab 06","num":6,"group":"RISK ASSESSMENT","title":"Build a Risk Scenario from a Business Concern","desc":"Leadership is worried about 'cloud risk' but cannot articulate anything more specific, which makes the concern impossible to assess or treat. You must translate that vague worry into a structured, assessable risk scenario with a clear cause, event, and impact.","objectives":["Convert a vague business concern into a structured risk scenario","Ensure the scenario includes a threat, vulnerability, asset, and business impact","Validate the scenario is plausible and relevant to the organization"],"console":{"host":"crisc-lab06","boot":["[SYS] risk-console v3.0 initializing","[SYS] loading scenario-builder templates","[SYS] cloud migration project brief attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the correct starting point for scenario development"},{"id":"t2","label":"Choose the elements a well-formed scenario must include"},{"id":"t3","label":"Choose the validation step before the scenario is used"}],"configs":[{"id":"c1","label":"What is the correct way to begin building a risk scenario from a vague concern?","options":["Decompose the concern into a specific threat acting on a specific asset","Immediately assign a numeric risk score without detail","Copy a generic scenario from an industry template unchanged","Escalate the vague concern directly to the board as-is"],"correct":"Decompose the concern into a specific threat acting on a specific asset","task":"t1"},{"id":"c2","label":"What must a well-formed risk scenario include?","options":["A threat, a vulnerability, an affected asset, and the resulting business impact","Only a dollar amount of potential loss","Only the name of the department involved","Only a reference to a compliance clause"],"correct":"A threat, a vulnerability, an affected asset, and the resulting business impact","task":"t2"},{"id":"c3","label":"What should be confirmed before the scenario is added to the register?","options":["That the scenario is plausible and relevant to the organization's context","That the scenario matches a scenario used by a competitor","That the scenario has already occurred at the organization","That the scenario is rated as low impact"],"correct":"That the scenario is plausible and relevant to the organization's context","task":"t3"}],"payload":{"label":"RUN the scenario builder","placeholder":"build-scenario --concern cloud-migration-risk","button":"Run","response":"[OUT] Concern decomposed into scenario: misconfigured storage bucket (vulnerability) exploited by external actor (threat) exposing customer PII (asset) causing regulatory fine and reputational loss (impact). Plausibility confirmed against current migration plan. Conclusion: vague concern converted into an assessable risk scenario."}}},
{"id":"Lab 07","num":7,"group":"RISK ASSESSMENT","title":"Score Inherent and Residual Risk for a Vendor Integration","desc":"A new API integration with a payments vendor has been proposed. You must score the inherent risk before any controls are considered, then score residual risk after existing controls are applied, so leadership sees the true value of the control environment.","objectives":["Score inherent risk without factoring in existing controls","Apply existing and planned controls to determine residual risk","Compare residual risk against risk appetite to determine if further action is needed"],"console":{"host":"crisc-lab07","boot":["[SYS] risk-console v3.0 initializing","[SYS] loading vendor integration risk assessment","[SYS] control catalog attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the correct basis for inherent risk"},{"id":"t2","label":"Choose the correct basis for residual risk"},{"id":"t3","label":"Choose the next step after residual risk is scored"}],"configs":[{"id":"c1","label":"How should inherent risk be scored?","options":["Likelihood and impact assuming no controls are in place","Likelihood and impact after all controls are applied","Based solely on the vendor's reputation","Based only on the contract value"],"correct":"Likelihood and impact assuming no controls are in place","task":"t1"},{"id":"c2","label":"How should residual risk be determined?","options":["By applying the effect of existing and planned controls to the inherent risk score","By using the same score as inherent risk, since controls rarely help","By asking the vendor to self-report their own residual risk","By ignoring controls until an audit confirms they work"],"correct":"By applying the effect of existing and planned controls to the inherent risk score","task":"t2"},{"id":"c3","label":"What should be done once residual risk is scored?","options":["Compare it to the organization's risk appetite to decide if further treatment is needed","Close the assessment regardless of the score","Report only the inherent risk score to leadership","Delete the inherent risk score since it is no longer relevant"],"correct":"Compare it to the organization's risk appetite to decide if further treatment is needed","task":"t3"}],"payload":{"label":"RUN the inherent/residual scoring model","placeholder":"score-risk --asset payments-api --mode inherent-residual","button":"Run","response":"[OUT] Inherent risk scored High (likelihood 4, impact 5); after TLS enforcement, API rate limiting, and vendor SOC 2 review applied, residual risk scored Medium (likelihood 2, impact 4); residual exceeds appetite threshold by one band. Conclusion: additional treatment required before go-live."}}},
{"id":"Lab 08","num":8,"group":"RISK ASSESSMENT","title":"Read a Risk Heat Map for Portfolio Prioritization","desc":"A portfolio of 40 IT risks has been scored and plotted on a 5x5 heat map, but the steering committee has limited time and wants to know which risks demand attention this quarter versus which can be monitored passively.","objectives":["Interpret heat map position as a function of likelihood and impact, not color alone","Prioritize risks in the high-likelihood, high-impact zone for immediate action","Recognize that low-likelihood, high-impact risks still require monitoring or contingency planning"],"console":{"host":"crisc-lab08","boot":["[SYS] risk-console v3.0 initializing","[SYS] loading 5x5 heat map (40 risks plotted)","[SYS] committee agenda template attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose what heat map position actually represents"},{"id":"t2","label":"Choose which risks should be prioritized for immediate action"},{"id":"t3","label":"Choose the correct treatment of low-likelihood, high-impact risks"}],"configs":[{"id":"c1","label":"What does a risk's position on the heat map represent?","options":["Its combined likelihood and impact score","Only how recently it was identified","The department that reported it","The number of controls already applied"],"correct":"Its combined likelihood and impact score","task":"t1"},{"id":"c2","label":"Which risks should the committee prioritize for immediate action this quarter?","options":["Risks in the high-likelihood, high-impact zone","Risks with the longest written descriptions","Risks first entered into the register chronologically","Risks owned by the most senior manager"],"correct":"Risks in the high-likelihood, high-impact zone","task":"t2"},{"id":"c3","label":"How should low-likelihood, high-impact risks be handled?","options":["Monitored with contingency plans rather than ignored","Removed from the register since they are unlikely","Treated identically to low-impact risks","Escalated only if they have already occurred"],"correct":"Monitored with contingency plans rather than ignored","task":"t3"}],"payload":{"label":"RUN the heat map prioritization query","placeholder":"prioritize-heatmap --quadrant high-high","button":"Run","response":"[OUT] 6 risks identified in high-likelihood/high-impact quadrant and queued for immediate committee review; 5 low-likelihood/high-impact risks flagged for contingency plan review. Conclusion: portfolio prioritized by heat map position, not report age."}}},
{"id":"Lab 09","num":9,"group":"RISK ASSESSMENT","title":"Choose Qualitative vs Quantitative Analysis for a Data Center Outage Scenario","desc":"The CFO wants a dollar-value loss estimate for a potential data center outage before approving a redundant site, while the risk team's usual practice is a simple high/medium/low rating. You must decide which analysis approach fits this specific decision.","objectives":["Recognize when quantitative analysis is warranted over qualitative rating","Confirm sufficient reliable data exists before committing to a quantitative model","Present results in the terms the decision-maker needs to act on"],"console":{"host":"crisc-lab09","boot":["[SYS] risk-console v3.0 initializing","[SYS] loading outage cost history dataset","[SYS] CFO decision brief attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose when quantitative analysis is the better fit"},{"id":"t2","label":"Choose the precondition for reliable quantitative results"},{"id":"t3","label":"Choose how results should be presented to the CFO"}],"configs":[{"id":"c1","label":"When is quantitative analysis the better choice over qualitative rating?","options":["When a financial decision requires a defensible dollar-value estimate","Whenever the risk team prefers more paperwork","Only when the risk is already rated as low","Never, qualitative ratings are always sufficient for capital decisions"],"correct":"When a financial decision requires a defensible dollar-value estimate","task":"t1"},{"id":"c2","label":"What must be confirmed before relying on a quantitative outage cost model?","options":["That sufficient reliable historical and cost data exists to support the estimate","That the CFO has already approved the budget","That the data center has never had an outage before","That no qualitative rating was ever produced"],"correct":"That sufficient reliable historical and cost data exists to support the estimate","task":"t2"},{"id":"c3","label":"How should the quantitative result be presented to the CFO?","options":["As an estimated annualized loss expectancy in financial terms tied to the redundancy decision","As a color-coded heat map only","As a generic high/medium/low label","As a narrative with no supporting figures"],"correct":"As an estimated annualized loss expectancy in financial terms tied to the redundancy decision","task":"t3"}],"payload":{"label":"RUN the quantitative loss model","placeholder":"model-loss --scenario datacenter-outage --method ale","button":"Run","response":"[OUT] Annualized loss expectancy calculated at $1.2M using 5-year outage history and revenue-per-hour data; redundant site cost $450K/year. Conclusion: quantitative model supports CFO's capital decision to invest in redundancy."}}},
{"id":"Lab 10","num":10,"group":"RISK ASSESSMENT","title":"Validate Control Design and Operating Effectiveness","desc":"A control that requires manager approval for privileged access changes exists on paper, but no one has verified whether it is actually followed. You must assess both whether the control is designed well and whether it operates as intended before relying on it to lower residual risk.","objectives":["Distinguish control design adequacy from operating effectiveness","Use evidence such as logs and samples rather than the control owner's assurance alone","Adjust the residual risk score if the control is not operating effectively"],"console":{"host":"crisc-lab10","boot":["[SYS] risk-console v3.0 initializing","[SYS] loading privileged access control description","[SYS] sample access logs attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the two dimensions a control assessment must cover"},{"id":"t2","label":"Choose the correct evidence source for testing"},{"id":"t3","label":"Choose the correct action if the control is not operating effectively"}],"configs":[{"id":"c1","label":"What two dimensions must a control assessment evaluate?","options":["Design adequacy and operating effectiveness","Cost and vendor reputation only","Only whether the policy document exists","Only whether the control owner is satisfied with it"],"correct":"Design adequacy and operating effectiveness","task":"t1"},{"id":"c2","label":"What evidence should be used to test whether the control actually operates?","options":["Sampled access logs and approval records","The control owner's verbal assurance only","The original policy draft only","Marketing material from the access tool vendor"],"correct":"Sampled access logs and approval records","task":"t2"},{"id":"c3","label":"What should happen if testing shows the control is not operating effectively?","options":["Increase the residual risk score and flag the control for remediation","Leave the residual risk score unchanged since the design is sound","Remove the control from the register entirely","Assume the sample was unrepresentative and stop testing"],"correct":"Increase the residual risk score and flag the control for remediation","task":"t3"}],"payload":{"label":"RUN the control effectiveness test","placeholder":"test-control --id privileged-access-approval --sample 25","button":"Run","response":"[OUT] Design rated adequate; testing of 25 sampled changes found 7 without documented manager approval (28% exception rate); control rated not operating effectively. Conclusion: residual risk score increased and remediation task opened."}}},
{"id":"Lab 11","num":11,"group":"RISK RESPONSE & REPORTING","title":"Select the Right Risk Response for a High-Severity Finding","desc":"A penetration test found an unauthenticated admin interface exposed to the internet on a system slated for decommission in six months. Leadership wants a response recommendation that balances the severity of the finding against the short remaining life of the system.","objectives":["Evaluate accept, mitigate, transfer, and avoid against cost, timeline, and risk appetite","Recognize when a compensating control is appropriate versus full remediation","Ensure the chosen response is proportionate to both severity and remaining system life"],"console":{"host":"crisc-lab11","boot":["[SYS] risk-console v3.0 initializing","[SYS] loading pentest finding CVE-severity-critical","[SYS] decommission schedule attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the response options that must be evaluated"},{"id":"t2","label":"Choose the proportionate response given the short remaining life"},{"id":"t3","label":"Choose what makes the chosen response defensible"}],"configs":[{"id":"c1","label":"What response options should be evaluated for this finding?","options":["Accept, mitigate, transfer, and avoid, weighed against cost and risk appetite","Only whether to accept the risk silently","Only whether to decommission immediately regardless of cost","Only whether to purchase cyber insurance"],"correct":"Accept, mitigate, transfer, and avoid, weighed against cost and risk appetite","task":"t1"},{"id":"c2","label":"Given six months until decommission, what is the most proportionate response?","options":["Mitigate quickly with network isolation and access restriction as a compensating control","Full application redesign before addressing the exposure","No action since the system will be retired anyway","Immediate shutdown of the system with no business impact analysis"],"correct":"Mitigate quickly with network isolation and access restriction as a compensating control","task":"t2"},{"id":"c3","label":"What makes the chosen response defensible to leadership?","options":["It is proportionate to the severity, cost, and remaining system life, and formally documented","It was the cheapest option available","It matches what a competitor did","It avoids involving senior management in the decision"],"correct":"It is proportionate to the severity, cost, and remaining system life, and formally documented","task":"t3"}],"payload":{"label":"RUN the response selection model","placeholder":"select-response --finding admin-interface-exposure","button":"Run","response":"[OUT] Network isolation and IP allowlisting deployed within 48 hours as compensating control; full remediation deferred to decommission date; decision documented and approved by system owner. Conclusion: response is proportionate and formally accepted."}}},
{"id":"Lab 12","num":12,"group":"RISK RESPONSE & REPORTING","title":"Draft a Risk Action Plan with Measurable Milestones","desc":"A mitigation decision has been made for an unpatched ERP vulnerability, but the initial plan is a single line reading 'patch when possible.' You must turn that into an action plan with owners, milestones, and a completion date leadership can hold the team to.","objectives":["Break a mitigation decision into discrete, assignable action steps","Assign an accountable owner and due date to each action step","Define a measurable completion criterion rather than a vague goal"],"console":{"host":"crisc-lab12","boot":["[SYS] risk-console v3.0 initializing","[SYS] loading ERP vulnerability remediation ticket","[SYS] action plan template attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose how the mitigation decision should be broken down"},{"id":"t2","label":"Choose what each action step must include"},{"id":"t3","label":"Choose the correct completion criterion"}],"configs":[{"id":"c1","label":"How should the mitigation decision be turned into an action plan?","options":["Broken into discrete, assignable steps with a logical sequence","Left as a single vague instruction to the IT team","Delegated entirely to the vendor with no internal tracking","Written only as a narrative summary for the board"],"correct":"Broken into discrete, assignable steps with a logical sequence","task":"t1"},{"id":"c2","label":"What must each action step in the plan include?","options":["An accountable owner and a specific due date","Only a general timeframe like 'this year'","Only the name of the risk it relates to","Nothing beyond a checkbox to mark done"],"correct":"An accountable owner and a specific due date","task":"t2"},{"id":"c3","label":"What is a measurable completion criterion for this plan?","options":["Patch deployed and verified across 100% of affected ERP instances by a stated date","Patch deployment attempted at least once","IT reports the task feels mostly done","No criterion is needed once a due date exists"],"correct":"Patch deployed and verified across 100% of affected ERP instances by a stated date","task":"t3"}],"payload":{"label":"RUN the action plan builder","placeholder":"build-action-plan --risk erp-unpatched-vuln","button":"Run","response":"[OUT] Plan built with 5 sequenced steps, each with a named owner and due date; completion criterion set to 100% verified patch deployment by Q3 close. Conclusion: mitigation decision converted into a trackable, accountable action plan."}}},
{"id":"Lab 13","num":13,"group":"RISK RESPONSE & REPORTING","title":"Track Risk Treatment Progress Without Losing Accountability","desc":"Twelve risk treatment action plans are in flight, but the monthly status report from IT simply says 'in progress' for nine of them with no detail. The risk committee needs a tracking approach that surfaces stalled items instead of masking them.","objectives":["Track treatment progress against milestones rather than accepting vague status labels","Distinguish on-track, at-risk, and overdue action items using objective criteria","Escalate stalled action plans to the accountable owner's management"],"console":{"host":"crisc-lab13","boot":["[SYS] risk-console v3.0 initializing","[SYS] loading 12 active treatment action plans","[SYS] milestone tracker attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the correct basis for tracking progress"},{"id":"t2","label":"Choose the criteria for status classification"},{"id":"t3","label":"Choose the correct action for a stalled item"}],"configs":[{"id":"c1","label":"What should treatment progress be tracked against?","options":["Defined milestones and due dates within the action plan","Whatever status word the assigned team chooses to report","The risk owner's general impression of progress","Nothing; only final completion matters"],"correct":"Defined milestones and due dates within the action plan","task":"t1"},{"id":"c2","label":"How should action items be classified as on-track, at-risk, or overdue?","options":["Using objective criteria such as milestone dates missed or approaching","Based on which team is assigned to the item","Based on how the risk was originally rated","By a vote of the risk committee each month"],"correct":"Using objective criteria such as milestone dates missed or approaching","task":"t2"},{"id":"c3","label":"What should happen when an action plan is stalled with no clear reason?","options":["Escalate to the accountable owner's management for intervention","Extend the due date automatically without review","Remove the item from tracking to simplify the report","Reassign it to a different, uninvolved team without context"],"correct":"Escalate to the accountable owner's management for intervention","task":"t3"}],"payload":{"label":"RUN the treatment tracking sweep","placeholder":"track-treatments --status all --flag-stalled","button":"Run","response":"[OUT] Of 12 action plans: 6 on-track, 3 at-risk (milestone due within 2 weeks, <50% complete), 3 overdue and escalated to owners' managers. Conclusion: vague 'in progress' status replaced with objective, actionable tracking."}}},
{"id":"Lab 14","num":14,"group":"RISK RESPONSE & REPORTING","title":"Report Risk to the Board in Business Terms","desc":"A draft board report lists CVSS scores, patch counts, and firewall rule changes, but the board asked for a five-minute summary of what could hurt the business and what is being done about it. You must translate the technical report into board-level risk communication.","objectives":["Translate technical detail into business impact and decision-relevant language","Lead with the risks that matter most to strategic objectives, not the longest list","State clearly what decision or action the board is being asked to make"],"console":{"host":"crisc-lab14","boot":["[SYS] risk-console v3.0 initializing","[SYS] loading technical vulnerability report","[SYS] board reporting template attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the correct translation approach"},{"id":"t2","label":"Choose how the report should be prioritized"},{"id":"t3","label":"Choose what the report must end with"}],"configs":[{"id":"c1","label":"How should technical findings be translated for the board?","options":["Into business impact and risk language tied to strategic objectives","Left in raw technical form so the board appears well-informed","Simplified by omitting all risk ratings","Translated only into cost figures with no context"],"correct":"Into business impact and risk language tied to strategic objectives","task":"t1"},{"id":"c2","label":"How should the report be prioritized for a five-minute board discussion?","options":["Lead with the risks most material to strategic objectives and risk appetite","List every finding in the order IT discovered them","Order alphabetically by system name","Order by which finding has the longest technical description"],"correct":"Lead with the risks most material to strategic objectives and risk appetite","task":"t2"},{"id":"c3","label":"What must the report clearly state at the end?","options":["The specific decision or action requested of the board","A restatement of every technical detail already covered","An apology for the volume of findings","Nothing further; the data should speak for itself"],"correct":"The specific decision or action requested of the board","task":"t3"}],"payload":{"label":"RUN the board report translation","placeholder":"translate-report --audience board --source technical-vuln-report","button":"Run","response":"[OUT] 34 technical findings consolidated into 3 business risk statements tied to revenue and reputation; report opens with highest-materiality item; closing slide requests board decision on $600K remediation budget. Conclusion: report is board-ready and decision-oriented."}}},
{"id":"Lab 15","num":15,"group":"RISK RESPONSE & REPORTING","title":"Assess Third-Party Risk Before Contract Renewal","desc":"A critical SaaS vendor's contract is up for renewal in 30 days. The vendor has not provided an updated SOC 2 report and had a publicized breach at another customer last quarter. You must assess whether the relationship's risk profile has changed enough to affect the renewal decision.","objectives":["Reassess third-party risk on material events, not only on a fixed renewal calendar","Require current attestation evidence rather than relying on outdated assurance","Tie the renewal decision to the vendor's current residual risk, not just cost and convenience"],"console":{"host":"crisc-lab15","boot":["[SYS] risk-console v3.0 initializing","[SYS] loading vendor risk profile: saas-vendor-042","[SYS] breach disclosure notice attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose when third-party risk should be reassessed"},{"id":"t2","label":"Choose the correct evidence requirement before renewal"},{"id":"t3","label":"Choose what the renewal decision should be based on"}],"configs":[{"id":"c1","label":"When should a vendor's risk profile be reassessed?","options":["When material events occur, such as a breach elsewhere, in addition to scheduled reviews","Only on the fixed annual renewal date regardless of events","Only if the vendor volunteers new information","Never, once onboarded a vendor's risk rating is permanent"],"correct":"When material events occur, such as a breach elsewhere, in addition to scheduled reviews","task":"t1"},{"id":"c2","label":"What should be required before renewing the contract?","options":["A current SOC 2 report or equivalent attestation reflecting present controls","The vendor's original attestation from three years ago","A verbal assurance from the vendor's sales representative","Nothing, since the vendor has been reliable in the past"],"correct":"A current SOC 2 report or equivalent attestation reflecting present controls","task":"t2"},{"id":"c3","label":"What should ultimately drive the renewal decision?","options":["The vendor's current residual risk relative to the organization's risk appetite","Switching cost and convenience alone","The length of the prior relationship alone","The vendor's marketing claims about their security program"],"correct":"The vendor's current residual risk relative to the organization's risk appetite","task":"t3"}],"payload":{"label":"RUN the third-party risk reassessment","placeholder":"reassess-vendor --id saas-vendor-042 --trigger breach-disclosure","button":"Run","response":"[OUT] Updated SOC 2 requested and reviewed; 2 exceptions noted in access control testing; residual risk re-scored from Medium to High pending remediation commitment. Conclusion: renewal held pending vendor corrective action plan."}}},
{"id":"Lab 16","num":16,"group":"RISK RESPONSE & REPORTING","title":"Design a Risk Exception Process That Doesn't Erode Governance","desc":"Business units have been bypassing the change control policy by emailing informal approvals to their own managers whenever a control can't be met on schedule. You must design a formal exception process that allows legitimate business flexibility without quietly eroding the control framework.","objectives":["Require documented justification and a compensating control for every exception","Set a mandatory expiration date so exceptions cannot become permanent by default","Route exception approval to a risk-authority role independent of the requester"],"console":{"host":"crisc-lab16","boot":["[SYS] risk-console v3.0 initializing","[SYS] loading informal exception email trail","[SYS] exception request template attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose what every exception request must include"},{"id":"t2","label":"Choose the correct duration rule for exceptions"},{"id":"t3","label":"Choose who should approve exception requests"}],"configs":[{"id":"c1","label":"What must accompany every exception request?","options":["Documented justification and a compensating control","Nothing beyond a manager's verbal agreement","A promise to comply next year","The requester's seniority level"],"correct":"Documented justification and a compensating control","task":"t1"},{"id":"c2","label":"How long should an approved exception remain valid?","options":["A defined, limited period with a mandatory expiration and review date","Indefinitely, until someone remembers to revisit it","Exactly one business day only","As long as the requester's manager remains in the role"],"correct":"A defined, limited period with a mandatory expiration and review date","task":"t2"},{"id":"c3","label":"Who should approve risk exception requests?","options":["A risk-authority role independent of the person requesting the exception","The same manager who requested the exception","Whoever is available in the office that day","No one; exceptions should be self-approved to save time"],"correct":"A risk-authority role independent of the person requesting the exception","task":"t3"}],"payload":{"label":"RUN the exception process validation","placeholder":"validate-exception-process --scope change-control","button":"Run","response":"[OUT] New process requires justification, compensating control, and independent risk-owner sign-off; all exceptions capped at 90 days with automatic expiration. Conclusion: exception process formalized without weakening the control framework."}}},
{"id":"Lab 17","num":17,"group":"TECHNOLOGY & SECURITY","title":"Set RTO and RPO for a Revenue-Critical Order System","desc":"The disaster recovery plan for the order management system was written five years ago and specifies a 24-hour recovery time with no defined recovery point objective. Revenue impact from downtime has grown substantially since then, and you must reset both targets to match current business need.","objectives":["Derive RTO from the maximum tolerable downtime the business can absorb","Derive RPO from the maximum acceptable data loss for the process","Confirm the recovery targets are achievable with current backup and failover capability"],"console":{"host":"crisc-lab17","boot":["[SYS] risk-console v3.0 initializing","[SYS] loading order-management BIA data","[SYS] backup and replication topology attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the correct basis for setting RTO"},{"id":"t2","label":"Choose the correct basis for setting RPO"},{"id":"t3","label":"Choose what must be confirmed before finalizing the targets"}],"configs":[{"id":"c1","label":"What should the recovery time objective be based on?","options":["The maximum downtime the business can tolerate before unacceptable impact","The convenience of the infrastructure team's shift schedule","The RTO used by an unrelated competitor","Whatever figure was documented five years ago"],"correct":"The maximum downtime the business can tolerate before unacceptable impact","task":"t1"},{"id":"c2","label":"What should the recovery point objective be based on?","options":["The maximum acceptable amount of data loss measured in time","The total size of the production database","The frequency of unrelated software updates","The RTO value, since they are the same metric"],"correct":"The maximum acceptable amount of data loss measured in time","task":"t2"},{"id":"c3","label":"What must be confirmed before finalizing new RTO/RPO targets?","options":["That current backup, replication, and failover capability can actually achieve them","That the targets look impressive in the DR document","That the previous targets are simply doubled","That no testing is required once targets are written down"],"correct":"That current backup, replication, and failover capability can actually achieve them","task":"t3"}],"payload":{"label":"RUN the recovery target calibration","placeholder":"calibrate-recovery --system order-management","button":"Run","response":"[OUT] BIA shows revenue loss becomes unacceptable after 2 hours; RTO reset to 2 hours, RPO reset to 15 minutes; replication topology tested and confirmed capable of meeting both targets. Conclusion: recovery objectives now reflect current business impact and are technically achievable."}}},
{"id":"Lab 18","num":18,"group":"TECHNOLOGY & SECURITY","title":"Assess Risk in an Accelerated DevOps Release Pipeline","desc":"A development team has moved to daily production deployments to keep pace with competitors, but security and risk review still assumes a monthly release cycle. You must redesign the risk assessment approach so it fits the new pipeline speed without becoming a bottleneck or a rubber stamp.","objectives":["Shift risk assessment left into the pipeline rather than as a final manual gate","Automate control checks that can be automated, reserving manual review for material changes","Maintain a documented risk decision trail even when reviews are automated"],"console":{"host":"crisc-lab18","boot":["[SYS] risk-console v3.0 initializing","[SYS] loading CI/CD pipeline topology","[SYS] release cadence: daily","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose where risk assessment should occur in the pipeline"},{"id":"t2","label":"Choose which checks should be automated versus manual"},{"id":"t3","label":"Choose what must be preserved despite automation"}],"configs":[{"id":"c1","label":"Where should risk assessment activity move to fit a daily release cadence?","options":["Earlier in the pipeline (shifted left) rather than as a single end-stage gate","Removed entirely to avoid slowing releases","Consolidated into one manual review per quarter","Moved entirely to the post-incident review stage"],"correct":"Earlier in the pipeline (shifted left) rather than as a single end-stage gate","task":"t1"},{"id":"c2","label":"How should checks be distributed between automation and manual review?","options":["Automate routine, repeatable checks; reserve manual review for material or high-risk changes","Automate everything including business-impact judgment calls","Manually review every single commit regardless of size","Automate nothing to preserve full manual control"],"correct":"Automate routine, repeatable checks; reserve manual review for material or high-risk changes","task":"t2"},{"id":"c3","label":"What must be preserved even when checks are automated?","options":["A documented, auditable trail of risk decisions made in the pipeline","Nothing, automated logs are unnecessary","A requirement that a human re-approve every automated pass manually","The original monthly review cadence in parallel"],"correct":"A documented, auditable trail of risk decisions made in the pipeline","task":"t3"}],"payload":{"label":"RUN the pipeline risk gate redesign","placeholder":"redesign-gates --pipeline ci-cd --cadence daily","button":"Run","response":"[OUT] Automated security and dependency scans added at build stage; manual review gate retained only for changes touching payment or auth code; all gate decisions logged with timestamp and approver. Conclusion: risk assessment now scales with daily release cadence and remains auditable."}}},
{"id":"Lab 19","num":19,"group":"TECHNOLOGY & SECURITY","title":"Evaluate Risk of a Multi-Cloud Migration","desc":"The organization is migrating workloads from a single data center to two different cloud providers to reduce concentration risk, but the migration itself introduces new risks around identity federation, data residency, and shared responsibility gaps. You must assess this transition risk before migration begins.","objectives":["Identify shared responsibility gaps that differ by cloud provider and service model","Assess data residency and sovereignty risk introduced by multi-cloud placement","Confirm identity federation is assessed as a distinct risk area, not assumed secure by default"],"console":{"host":"crisc-lab19","boot":["[SYS] risk-console v3.0 initializing","[SYS] loading multi-cloud migration plan","[SYS] shared responsibility matrices (provider A, provider B) attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose what must be clarified per provider before migration"},{"id":"t2","label":"Choose the risk area tied to workload placement across regions"},{"id":"t3","label":"Choose the correct treatment of identity federation risk"}],"configs":[{"id":"c1","label":"What must be clarified for each cloud provider before migration?","options":["The shared responsibility boundary for security controls under that provider's service model","The provider's marketing tagline","The provider's stock price history","Nothing, since all providers use identical responsibility models"],"correct":"The shared responsibility boundary for security controls under that provider's service model","task":"t1"},{"id":"c2","label":"What risk area arises from placing workloads across cloud regions and providers?","options":["Data residency and sovereignty risk","Only aesthetic differences in the management console","Risk that only affects the vendor, not the organization","No new risk, since data is still 'in the cloud'"],"correct":"Data residency and sovereignty risk","task":"t2"},{"id":"c3","label":"How should identity federation across multiple clouds be treated?","options":["As a distinct risk area requiring its own explicit assessment","As automatically secure because both providers support SSO","As out of scope since it is a technical implementation detail only","As equivalent in risk to a single-cloud identity setup"],"correct":"As a distinct risk area requiring its own explicit assessment","task":"t3"}],"payload":{"label":"RUN the multi-cloud risk assessment","placeholder":"assess-migration --providers a,b --focus shared-responsibility","button":"Run","response":"[OUT] Shared responsibility gap identified in provider B's default logging config; data residency confirmed compliant for regulated records; identity federation assessed separately and flagged for MFA enforcement gap. Conclusion: migration risk assessed with 3 findings requiring remediation before cutover."}}},
{"id":"Lab 20","num":20,"group":"TECHNOLOGY & SECURITY","title":"Assess Risk of a Planned Emergency Change","desc":"A critical vulnerability requires an emergency patch to production during business hours, bypassing the normal change advisory board review window. You must assess the risk of the emergency change itself, balancing the urgency of the fix against the risk of an unreviewed change to a live system.","objectives":["Weigh the risk of delaying the fix against the risk of an expedited, less-reviewed change","Require a compensating review step even when the normal CAB cycle is bypassed","Ensure a rollback plan exists and is tested before the emergency change is executed"],"console":{"host":"crisc-lab20","boot":["[SYS] risk-console v3.0 initializing","[SYS] loading emergency change request EC-2291","[SYS] rollback procedure draft attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the correct risk trade-off to evaluate"},{"id":"t2","label":"Choose what must still occur despite bypassing the normal CAB cycle"},{"id":"t3","label":"Choose the precondition before executing the emergency change"}],"configs":[{"id":"c1","label":"What trade-off must be evaluated for an emergency change?","options":["The risk of delaying the fix versus the risk of an expedited, less-reviewed change","Only the convenience of the engineer available at the time","Only whether leadership is awake to approve it","Whether the change can be made without telling the change owner"],"correct":"The risk of delaying the fix versus the risk of an expedited, less-reviewed change","task":"t1"},{"id":"c2","label":"What must still happen even when the normal CAB review is bypassed?","options":["A compensating review by an accountable authority, even if abbreviated","Nothing; urgency removes the need for any oversight","A public announcement to all customers before the change","A full board vote before any emergency change"],"correct":"A compensating review by an accountable authority, even if abbreviated","task":"t2"},{"id":"c3","label":"What must exist before the emergency change is executed?","options":["A tested rollback plan in case the change fails","A guarantee that the change cannot possibly fail","Approval from the vendor's marketing team","A commitment to skip rollback planning to save time"],"correct":"A tested rollback plan in case the change fails","task":"t3"}],"payload":{"label":"RUN the emergency change risk assessment","placeholder":"assess-change --id EC-2291 --mode emergency","button":"Run","response":"[OUT] Delay risk (active exploitation) rated higher than expedited-change risk; abbreviated review completed by on-call change authority; rollback script tested successfully in staging before production execution. Conclusion: emergency change risk-assessed, reviewed, and executed with a validated rollback path."}}},
];
